ctx.lineCap = "round";
ctx.lineJoin = "round";

// Theme & palette
var C = {
  primary: "#1d4ed8",
  secondary: "#7c3aed",
  accent: "#f97316",
  highlight: "#10b981",
  danger: "#dc2626",
  panelBg: "rgba(250, 245, 235, 0.92)",
  panelBorder: "rgba(0,0,0,0.1)",
  text: "#1e293b",
  muted: "#64748b"
};

// Init params
runtimeState.params = runtimeState.params || {};
if (runtimeState.params.primaryTurns == null) runtimeState.params.primaryTurns = 60;
if (runtimeState.params.secondaryTurns == null) runtimeState.params.secondaryTurns = 120;
if (runtimeState.params.inputVoltage == null) runtimeState.params.inputVoltage = 20;
if (runtimeState.params.frequency == null) runtimeState.params.frequency = 60;
if (runtimeState.params.loadResistance == null) runtimeState.params.loadResistance = 50;
if (runtimeState.params.stepIndex == null) runtimeState.params.stepIndex = 0;

var Np = runtimeState.params.primaryTurns;
var Ns = runtimeState.params.secondaryTurns;
var Vp = runtimeState.params.inputVoltage;
var f = runtimeState.params.frequency;
var R = runtimeState.params.loadResistance;

var w = canvas.width, h = canvas.height;
var cx = w * 0.5, cy = h * 0.5;
var p = runtimeState.pointer;

// Derived idealized values
var ratio = Ns / Math.max(1, Np);
var Vs = Vp * ratio;
var Is = Vs / Math.max(1, R);
var Ip = Is * (Ns / Math.max(1, Np)); // simple visual scaling
var power = Vs * Is;
var overload = (Vp >= 80 && R <= 15) || power > 800;

// AC phase
var phase = Math.sin(time * Math.PI * 2 * f / 60);
var flux = phase * (Vp / 120);

// Layout
var coreW = Math.min(380, w * 0.42);
var coreH = Math.min(220, h * 0.36);
var coreX = cx - coreW / 2;
var coreY = cy - coreH / 2;

// Core
ctx.lineWidth = 3;
ctx.strokeStyle = overload ? C.danger : C.secondary;
ctx.strokeRect(coreX, coreY, coreW, coreH);
ctx.lineWidth = 1.2;
ctx.strokeStyle = "rgba(124,58,237,0.35)";
ctx.strokeRect(coreX + 18, coreY + 18, coreW - 36, coreH - 36);

// Flux wave inside core tunnel
ctx.beginPath();
ctx.lineWidth = 2;
ctx.strokeStyle = C.secondary;
for (var i = 0; i <= 160; i++) {
  var t = i / 160;
  var x = coreX + 24 + t * (coreW - 48);
  var y = cy + Math.sin(t * Math.PI * 6 - time * 4) * (10 + 12 * Math.abs(flux));
  if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
}
ctx.stroke();

// Coils
function drawCoil(x, y, height, turns, color, active) {
  var loops = Math.max(4, Math.round(turns / 10));
  var step = height / loops;
  ctx.lineWidth = 3;
  ctx.strokeStyle = active ? C.highlight : color;
  for (var i = 0; i < loops; i++) {
    var yy = y - height / 2 + i * step + step / 2;
    ctx.beginPath();
    ctx.arc(x, yy, Math.max(6, step * 0.45), -Math.PI * 0.5, Math.PI * 1.5);
    ctx.stroke();
  }
}

var leftX = coreX - 34;
var rightX = coreX + coreW + 34;
drawCoil(leftX, cy, coreH * 0.86, Np, C.primary, true);
drawCoil(rightX, cy, coreH * 0.86, Ns, C.primary, false);

// Windmill analogy icons
function windmill(x, y, r, spin, color) {
  ctx.save();
  ctx.translate(x, y);
  ctx.rotate(spin);
  ctx.lineWidth = 2;
  ctx.strokeStyle = color;
  for (var i = 0; i < 3; i++) {
    ctx.rotate((Math.PI * 2) / 3);
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.lineTo(r, 0);
    ctx.stroke();
  }
  ctx.restore();
  ctx.beginPath();
  ctx.fillStyle = color;
  ctx.arc(x, y, 3, 0, Math.PI * 2);
  ctx.fill();
}
windmill(leftX - 26, cy - coreH * 0.35, 14, time * (0.8 + Math.abs(flux) * 2.5), C.primary);
windmill(rightX + 26, cy - coreH * 0.35, 14, time * (0.6 + Math.abs(flux) * 1.8), C.secondary);

// Current arrows
function arrow(x1, y1, x2, y2, color, lw) {
  var dx = x2 - x1, dy = y2 - y1;
  var a = Math.atan2(dy, dx);
  ctx.strokeStyle = color;
  ctx.fillStyle = color;
  ctx.lineWidth = lw;
  ctx.beginPath();
  ctx.moveTo(x1, y1); ctx.lineTo(x2, y2); ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(x2, y2);
  ctx.lineTo(x2 - 10 * Math.cos(a - 0.35), y2 - 10 * Math.sin(a - 0.35));
  ctx.lineTo(x2 - 10 * Math.cos(a + 0.35), y2 - 10 * Math.sin(a + 0.35));
  ctx.closePath();
  ctx.fill();
}
var iScaleP = Math.min(1, Math.abs(Ip) / 8);
var iScaleS = Math.min(1, Math.abs(Is) / 8);
arrow(leftX - 80, cy + 70, leftX - 20 + 22 * phase, cy + 70, C.accent, 2 + iScaleP * 2);
arrow(rightX + 20, cy + 70, rightX + 80 + 22 * phase, cy + 70, C.accent, 2 + iScaleS * 2);

// Labels
ctx.save();
ctx.fillStyle = C.text;
ctx.font = "11px system-ui, sans-serif";
ctx.letterSpacing = "0.15em";
ctx.textAlign = "center";
ctx.fillText("PRIMARY (NP)", leftX - 6, cy + coreH * 0.52);
ctx.fillText("SECONDARY (NS)", rightX + 6, cy + coreH * 0.52);
ctx.fillText("SHARED CORE / FLUX TUNNEL", cx, coreY - 10);
ctx.restore();

ctx.textAlign = "left";
ctx.textBaseline = "alphabetic";

// Metrics panel
var px = 16, py = 16, pw = 280, ph = 140;
ctx.fillStyle = C.panelBg;
ctx.strokeStyle = C.panelBorder;
ctx.lineWidth = 1;
ctx.beginPath(); ctx.roundRect(px, py, pw, ph, 12); ctx.fill(); ctx.stroke();
ctx.fillStyle = C.muted;
ctx.font = "10px system-ui, sans-serif";
ctx.fillText("TRANSFORMER READOUT", px + 14, py + 18);
ctx.fillStyle = C.text;
ctx.font = "700 16px ui-monospace, monospace";
ctx.fillText("Vs≈" + Vs.toFixed(1) + "V   Is≈" + Is.toFixed(2) + "A", px + 14, py + 44);
ctx.font = "700 13px ui-monospace, monospace";
ctx.fillText("Vp=" + Vp.toFixed(1) + "V  Np=" + Math.round(Np), px + 14, py + 66);
ctx.fillText("Ns=" + Math.round(Ns) + "  Ns/Np=" + ratio.toFixed(2), px + 14, py + 86);
ctx.fillText("Rload=" + R.toFixed(1) + "Ω  P≈" + power.toFixed(1) + "W", px + 14, py + 106);
if (overload) { ctx.fillStyle = C.danger; ctx.fillText("WARNING: HIGH DEMAND / SATURATION RISK", px + 14, py + 126); }

// Sliders
var sliders = [
  { key:"primaryTurns", label:"PRIMARY TURNS (NP)", min:10, max:200, step:1 },
  { key:"secondaryTurns", label:"SECONDARY TURNS (NS)", min:10, max:400, step:1 },
  { key:"inputVoltage", label:"INPUT VOLTAGE (VP, RMS)", min:1, max:120, step:0.1 },
  { key:"frequency", label:"AC FREQUENCY", min:1, max:120, step:1 },
  { key:"loadResistance", label:"LOAD RESISTANCE (RLOAD)", min:1, max:200, step:0.1 }
];
var sx = 16, sy = h - 210, sw = Math.min(430, w * 0.5), sh = 194;
ctx.fillStyle = C.panelBg; ctx.strokeStyle = C.panelBorder;
ctx.beginPath(); ctx.roundRect(sx, sy, sw, sh, 12); ctx.fill(); ctx.stroke();
for (var si = 0; si < sliders.length; si++) {
  var s = sliders[si];
  var y = sy + 24 + si * 34;
  var tx1 = sx + 16, tx2 = sx + sw - 16;
  var v = runtimeState.params[s.key];
  var tnorm = (v - s.min) / (s.max - s.min);
  var kx = tx1 + tnorm * (tx2 - tx1);
  ctx.strokeStyle = "rgba(30,41,59,0.22)"; ctx.lineWidth = 1.4;
  ctx.beginPath(); ctx.moveTo(tx1, y); ctx.lineTo(tx2, y); ctx.stroke();
  ctx.strokeStyle = C.primary; ctx.lineWidth = 3;
  ctx.beginPath(); ctx.moveTo(tx1, y); ctx.lineTo(kx, y); ctx.stroke();
  ctx.fillStyle = C.primary; ctx.beginPath(); ctx.arc(kx, y, 6, 0, Math.PI * 2); ctx.fill();
  ctx.fillStyle = C.text; ctx.font = "11px system-ui, sans-serif";
  ctx.fillText(s.label, tx1, y - 10);
  ctx.font = "700 11px ui-monospace, monospace";
  ctx.fillText((Math.round(v*10)/10).toString(), tx2 - 40, y - 10);

  if (p && p.down && p.x >= tx1 - 8 && p.x <= tx2 + 8 && p.y >= y - 10 && p.y <= y + 10) {
    var nt = Math.max(0, Math.min(1, (p.x - tx1) / (tx2 - tx1)));
    var nv = s.min + nt * (s.max - s.min);
    var q = s.step || 1;
    runtimeState.params[s.key] = Math.round(nv / q) * q;
  }
}

// Scaffolded steps panel
var steps = [
  "Set frequency to ~60 and increase input voltage to 30. Changing current creates changing flux.",
  "Keep primaryTurns fixed and raise secondaryTurns to about 2x primaryTurns. Vs/Vp ≈ Ns/Np.",
  "Reduce secondaryTurns to about half of primaryTurns. Observe step-down voltage.",
  "With secondaryTurns < primaryTurns, lower loadResistance (heavy load). Current arrows grow.",
  "Raise inputVoltage with heavy load and watch overload warning coloration."
];
var ix = Math.max(320, w - 420), iy = 16, iw = Math.min(404, w - ix - 16), ih = 142;
ctx.fillStyle = C.panelBg; ctx.strokeStyle = C.panelBorder;
ctx.beginPath(); ctx.roundRect(ix, iy, iw, ih, 12); ctx.fill(); ctx.stroke();

var idx = Math.max(0, Math.min(4, runtimeState.params.stepIndex|0));
runtimeState.params.stepIndex = idx;

var leftBtn = { x: ix + 14, y: iy + ih - 34, w: 28, h: 22 };
var rightBtn = { x: ix + 50, y: iy + ih - 34, w: 28, h: 22 };
if (p && p.clicked) {
  if (p.x >= leftBtn.x && p.x <= leftBtn.x + leftBtn.w && p.y >= leftBtn.y && p.y <= leftBtn.y + leftBtn.h) runtimeState.params.stepIndex = Math.max(0, idx - 1);
  if (p.x >= rightBtn.x && p.x <= rightBtn.x + rightBtn.w && p.y >= rightBtn.y && p.y <= rightBtn.y + rightBtn.h) runtimeState.params.stepIndex = Math.min(4, idx + 1);
}

ctx.fillStyle = C.muted; ctx.font = "10px system-ui, sans-serif";
ctx.fillText("SCAFFOLDED STEPS", ix + 14, iy + 18);
ctx.fillStyle = C.text; ctx.font = "11px system-ui, sans-serif";
ctx.fillText("Step " + (runtimeState.params.stepIndex + 1) + " / 5", ix + iw - 86, iy + 18);
ctx.fillStyle = C.text;
var msg = steps[runtimeState.params.stepIndex];
var words = msg.split(" "), line = "", yy = iy + 42;
for (var wi = 0; wi < words.length; wi++) {
  var test = line + words[wi] + " ";
  if (ctx.measureText(test).width > iw - 28) { ctx.fillText(line, ix + 14, yy); line = words[wi] + " "; yy += 16; }
  else line = test;
}
ctx.fillText(line, ix + 14, yy);

ctx.strokeStyle = C.panelBorder; ctx.lineWidth = 1;
ctx.beginPath(); ctx.roundRect(leftBtn.x, leftBtn.y, leftBtn.w, leftBtn.h, 6); ctx.stroke();
ctx.beginPath(); ctx.roundRect(rightBtn.x, rightBtn.y, rightBtn.w, rightBtn.h, 6); ctx.stroke();
ctx.fillStyle = C.text; ctx.fillText("←", leftBtn.x + 10, leftBtn.y + 15); ctx.fillText("→", rightBtn.x + 10, rightBtn.y + 15);

